import React, { useState } from "react";
import { useNavigate } from "react-router-dom";
import { XMarkIcon } from "@heroicons/react/24/solid";
import FloatingInput from "../component/FloatingInput";

export default function Login() {
  const navigate = useNavigate();

  const [formData, setFormData] = useState({
    username: "",
    password: "",
  });

  const [error, setError] = useState("");
  const [success, setSuccess] = useState("");

  const BASE_URL = "http://localhost:8086";

  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
    setError("");
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    if (!formData.username || !formData.password) {
      setError("All fields are required");
      return;
    }

    try {
      const res = await fetch(`${BASE_URL}/user/login`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(formData),
      });

      if (res.ok) {
        setSuccess("Login successful!");

        setTimeout(() => {
          navigate("/"); // or dashboard
        }, 800);
      } else {
        setError("Invalid username or password");
      }
    } catch {
      setError("Cannot connect to server");
    }
  };

  return (
    <div className="fixed inset-0 flex items-center justify-center">
      <div className="relative w-[500px] p-8 rounded-2xl backdrop-blur-xl bg-white/20 border border-white/30 shadow-2xl">

        <button
          onClick={() => navigate("/")}
          className="absolute top-3 right-3 text-white"
        >
          <XMarkIcon className="w-6 h-6" />
        </button>

        <h2 className="text-2xl font-bold text-white text-center mb-6">
          Login
        </h2>

        {success && <p className="text-green-300 text-center">{success}</p>}
        {error && <p className="text-red-300 text-center">{error}</p>}

        <form onSubmit={handleSubmit} className="space-y-4">
          <FloatingInput
            name="username"
            label="Username"
            value={formData.username}
            onChange={handleChange}
          />

          <FloatingInput
            name="password"
            type="password"
            label="Password"
            value={formData.password}
            onChange={handleChange}
          />

          <button className="w-full py-2 rounded-lg bg-white/30 text-white">
            Login
          </button>
        </form>

        {/* LINKS */}
        <div className="text-center mt-4 text-sm text-white/80 space-y-2">

          <p>
            Don't have an account?{" "}
            <span
              onClick={() => navigate("/register")}
              className="text-sky-400 cursor-pointer hover:underline"
            >
              Register
            </span>
          </p>

          <p>
            Are you staff?{" "}
            <span
              onClick={() => navigate("/staff-login")}
              className="text-yellow-300 cursor-pointer hover:underline"
            >
              Staff Login
            </span>
          </p>
        </div>
      </div>
    </div>
  );
}
